import type { ReactNode } from "react";

export function AIConversation({ children }: { children: ReactNode }) {
  return <div className="flex flex-col gap-3 rounded-lg border p-4">{children}</div>;
}

import type { UIMessage } from "ai";

export function AIMessage({ message }: { message: UIMessage }) {
  return (
    <article className="rounded-md bg-muted p-3 text-sm">
      <div className="mb-1 font-medium capitalize">{message.role}</div>
      {message.parts.map((part, index) =>
        part.type === "text" ? <p key={index}>{part.text}</p> : null,
      )}
    </article>
  );
}

"use client";

import type { FormEvent } from "react";

export function AIPromptInput({
  disabled,
  onSubmit,
  onValueChange,
  value,
}: {
  disabled?: boolean;
  onSubmit: () => void;
  onValueChange: (value: string) => void;
  value: string;
}) {
  function submit(event: FormEvent<HTMLFormElement>) {
    event.preventDefault();
    onSubmit();
  }

  return (
    <form className="flex gap-2" onSubmit={submit}>
      <textarea
        className="min-h-24 flex-1 rounded-md border bg-background p-3 text-sm"
        disabled={disabled}
        value={value}
        onChange={(event) => onValueChange(event.target.value)}
        placeholder="Ask a question..."
      />
      <button className="rounded-md border px-3 text-sm" disabled={disabled} type="submit">
        Send
      </button>
    </form>
  );
}

type AIChatStatus = "submitted" | "streaming" | "ready" | "error";

export function AIStatus({ status }: { status: AIChatStatus }) {
  if (status === "ready") return null;

  return (
    <p className="text-sm text-muted-foreground" role="status">
      {status === "submitted" ? "Thinking..." : "Streaming response..."}
    </p>
  );
}

export { AIConversation } from "./conversation";
export { AIMessage } from "./message";
export { AIPromptInput } from "./prompt-input";
export { AIStatus } from "./status";
